/* Forta bilingual language switcher — sits directly under the privacy line, inside the form, re-inserted on each step render */
(function(){
  function buildBar(){
    var path=location.pathname, isEs=path.indexOf('/es/')===0;
    var enHref=isEs?(path.replace(/^\/es/,'')||'/'):path;
    var esHref=isEs?path:'/es'+path;
    function link(href,label,active){
      return '<a href="'+href+'"'+(active?' aria-current="true"':'')+' style="text-decoration:none;padding:6px 14px;border-radius:999px;border:1px solid rgba(87,31,78,.35);'+(active?'background:#571f4e;color:#fff;':'background:#fff;color:#571f4e;')+'">'+label+'</a>';
    }
    var bar=document.createElement('div');
    bar.id='hf-langbar';
    bar.setAttribute('style','display:flex;justify-content:center;gap:8px;margin:14px 0 0;font-family:Manrope,system-ui,sans-serif;font-size:13px;font-weight:600');
    bar.innerHTML=link(enHref,'English',!isEs)+link(esHref,'Español',isEs);
    return bar;
  }
  function place(mount){
    var priv=mount.querySelector('.hf-privacy'); if(!priv)return;
    var bar=document.getElementById('hf-langbar');
    if(bar&&priv.nextSibling===bar)return;      /* already correctly placed -> no-op (prevents observer loop) */
    if(!bar)bar=buildBar();
    priv.parentNode.insertBefore(bar,priv.nextSibling);
  }
  function boot(){
    var mount=document.getElementById('lead-form'); if(!mount)return;
    new MutationObserver(function(){place(mount);}).observe(mount,{childList:true,subtree:true});
    place(mount);
  }
  if(document.readyState==='loading')document.addEventListener('DOMContentLoaded',boot);else boot();
})();
